@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&display=swap');

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: 'Inter', sans-serif;
  background: #d6e8f7;
  min-height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 20px;
}

/* ─── Phone Frame ─────────────────────────────────────── */
.phone-frame {
  width: 390px;
  min-height: 844px;
  background: #ffffff;
  border-radius: 50px;
  box-shadow:
    0 0 0 10px #1a1a2e,
    0 0 0 12px #2a2a4e,
    0 40px 80px rgba(0,0,0,0.35);
  overflow: hidden;
  position: relative;
  display: flex;
  flex-direction: column;
}

/* Notch */
.phone-frame::before {
  content: '';
  position: absolute;
  top: 0;
  left: 50%;
  transform: translateX(-50%);
  width: 120px;
  height: 30px;
  background: #1a1a2e;
  border-radius: 0 0 20px 20px;
  z-index: 100;
}

/* ─── Screen ──────────────────────────────────────────── */
.ob-screen {
  flex: 1;
  background: linear-gradient(175deg, #eaf3ff 0%, #f5faff 45%, #ffffff 100%);
  display: flex;
  flex-direction: column;
  padding: 0;
  animation: fadeSlideIn 0.4s ease forwards;
  min-height: 844px;
}

@keyframes fadeSlideIn {
  from { opacity: 0; transform: translateX(30px); }
  to   { opacity: 1; transform: translateX(0); }
}

/* ─── Status Bar ──────────────────────────────────────── */
.status-bar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 14px 28px 0;
  height: 48px;
}

.status-time {
  font-size: 13px;
  font-weight: 600;
  color: #1a2b4b;
}

.status-icons {
  display: flex;
  gap: 5px;
  align-items: center;
}

.status-icons i {
  font-size: 11px;
  color: #1a2b4b;
}

.battery-text {
  font-size: 11px;
  font-weight: 600;
  color: #1a2b4b;
}

/* ─── Header ──────────────────────────────────────────── */
.ob-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 10px 24px 8px;
}

.logo-wrap {
  display: flex;
  align-items: center;
  gap: 8px;
}

.logo-wrap img {
  height: 38px;
  object-fit: contain;
}

.skip-btn {
  font-size: 14px;
  font-weight: 500;
  color: #2563eb;
  text-decoration: none;
  padding: 4px 8px;
  border-radius: 8px;
  transition: background 0.2s;
}

.skip-btn:hover {
  background: rgba(37,99,235,0.08);
}

/* ─── Title Block ─────────────────────────────────────── */
.ob-text {
  padding: 4px 28px 10px;
  text-align: center;
}

.ob-title {
  font-size: 26px;
  font-weight: 800;
  color: #1a2b4b;
  line-height: 1.25;
  margin-bottom: 10px;
  letter-spacing: -0.3px;
}

.ob-subtitle {
  font-size: 14px;
  font-weight: 400;
  color: #7a8cad;
  line-height: 1.55;
}

/* ─── Illustration Area ───────────────────────────────── */
.illustration-wrap {
  position: relative;
  flex: 1;
  margin: 0 10px;
  min-height: 320px;
}

.ob-illus {
  width: 72%;
  height: 100%;
  object-fit: contain;
  position: absolute;
  left: 50%;
  top: 50%;
  transform: translate(-50%, -50%);
  z-index: 1;
}

/* ─── Metric Cards (Screen 1) ─────────────────────────── */
.metric-card {
  position: absolute;
  background: #ffffff;
  border-radius: 18px;
  padding: 12px 14px;
  box-shadow: 0 6px 24px rgba(37,99,235,0.10), 0 2px 8px rgba(0,0,0,0.06);
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 3px;
  z-index: 10;
  animation: floatCard 3s ease-in-out infinite;
  min-width: 78px;
}

.metric-card:nth-child(2) { animation-delay: 0s; }
.metric-card:nth-child(3) { animation-delay: 0.7s; }
.metric-card:nth-child(4) { animation-delay: 1.4s; }
.metric-card:nth-child(5) { animation-delay: 2.1s; }

@keyframes floatCard {
  0%,100% { transform: translateY(0px); }
  50%      { transform: translateY(-5px); }
}

.card-icon {
  width: 38px;
  height: 38px;
  border-radius: 12px;
  display: flex;
  align-items: center;
  justify-content: center;
  margin-bottom: 4px;
}

.card-icon i { font-size: 18px; }

.ic-red    { background: #fff0f0; color: #e84040; }
.ic-blue   { background: #eef5ff; color: #2563eb; }
.ic-teal   { background: #e6faf5; color: #0ea98b; }
.ic-purple { background: #f3f0ff; color: #7c3aed; }
.ic-green  { background: #e8faf2; color: #16a34a; }
.ic-indigo { background: #eef2ff; color: #4f46e5; }

.card-value {
  font-size: 17px;
  font-weight: 700;
  color: #1a2b4b;
  line-height: 1;
}

.card-unit {
  font-size: 11px;
  font-weight: 500;
  color: #9aadc9;
}

/* Card positions – screen 1 */
.pos-tl { top: 20px;  left: 0px; }
.pos-tr { top: 20px;  right: 0px; }
.pos-bl { bottom: 30px; left: 0px; }
.pos-br { bottom: 30px; right: 0px; }

/* ─── Feature Cards (Screen 2) ───────────────────────── */
.feature-card {
  position: absolute;
  background: #ffffff;
  border-radius: 18px;
  padding: 14px 16px;
  box-shadow: 0 6px 24px rgba(37,99,235,0.10), 0 2px 8px rgba(0,0,0,0.06);
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 6px;
  z-index: 10;
  min-width: 86px;
  animation: floatCard 3s ease-in-out infinite;
}

.feature-card:nth-child(2) { animation-delay: 0s; }
.feature-card:nth-child(3) { animation-delay: 0.8s; }
.feature-card:nth-child(4) { animation-delay: 1.6s; }
.feature-card:nth-child(5) { animation-delay: 2.4s; }

.feature-card .card-label {
  font-size: 12px;
  font-weight: 600;
  color: #1a2b4b;
  text-align: center;
  line-height: 1.3;
}

/* Bluetooth floating badge */
.bt-badge {
  position: absolute;
  right: 8px;
  top: 50%;
  transform: translateY(-50%);
  width: 52px;
  height: 52px;
  background: #eef5ff;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 10;
  box-shadow: 0 4px 16px rgba(37,99,235,0.15);
  animation: pulse 2s ease-in-out infinite;
}

.bt-badge i {
  font-size: 22px;
  color: #2563eb;
}

@keyframes pulse {
  0%,100% { box-shadow: 0 4px 16px rgba(37,99,235,0.15); }
  50%      { box-shadow: 0 4px 28px rgba(37,99,235,0.35); }
}

/* ─── Insight Cards (Screen 3) ───────────────────────── */
.insight-card {
  position: absolute;
  background: #ffffff;
  border-radius: 18px;
  padding: 12px 14px;
  box-shadow: 0 6px 24px rgba(37,99,235,0.10), 0 2px 8px rgba(0,0,0,0.06);
  display: flex;
  flex-direction: column;
  gap: 4px;
  z-index: 10;
  min-width: 100px;
  animation: floatCard 3s ease-in-out infinite;
}

.insight-card:nth-child(2) { animation-delay: 0s; }
.insight-card:nth-child(3) { animation-delay: 1s; }
.insight-card:nth-child(4) { animation-delay: 2s; }

.insight-label {
  font-size: 12px;
  font-weight: 600;
  color: #1a2b4b;
  margin-top: 2px;
}

.insight-status {
  font-size: 12px;
  font-weight: 600;
}

.status-good    { color: #16a34a; }
.status-low     { color: #16a34a; }
.status-warning { color: #f59e0b; }

.wave-svg {
  width: 60px;
  height: 18px;
  margin-top: 2px;
}

/* ─── Footer ──────────────────────────────────────────── */
.ob-footer {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 20px 28px 36px;
}

.dots {
  display: flex;
  gap: 7px;
  align-items: center;
}

.dot {
  width: 9px;
  height: 9px;
  border-radius: 50%;
  background: #ccd9ee;
  transition: all 0.3s ease;
}

.dot.active {
  width: 24px;
  border-radius: 5px;
  background: #2563eb;
}

.btn-next {
  display: flex;
  align-items: center;
  gap: 8px;
  background: #2563eb;
  color: #ffffff;
  text-decoration: none;
  font-size: 15px;
  font-weight: 600;
  padding: 14px 28px;
  border-radius: 50px;
  box-shadow: 0 6px 20px rgba(37,99,235,0.35);
  transition: all 0.25s ease;
  letter-spacing: 0.2px;
}

.btn-next:hover {
  background: #1d4ed8;
  box-shadow: 0 8px 28px rgba(37,99,235,0.45);
  transform: translateY(-1px);
}

.btn-next i {
  font-size: 14px;
}

/* ─── Responsive (actual mobile) ─────────────────────── */
@media (max-width: 430px) {
  body {
    background: linear-gradient(175deg, #eaf3ff 0%, #f5faff 45%, #ffffff 100%);
    padding: 0;
  }

  .phone-frame {
    width: 100%;
    min-height: 100vh;
    border-radius: 0;
    box-shadow: none;
  }

  .phone-frame::before {
    display: none;
  }

  .ob-screen {
    min-height: 100vh;
  }
}

