@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&display=swap');

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: 'Inter', sans-serif;
  background: #d6e8f7;
  min-height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 20px;
}

/* ─── Phone Frame ─────────────────────────────────── */
.phone-frame {
  width: 390px;
  height: 844px;
  background: #f4f7fb;
  border-radius: 50px;
  box-shadow:
    0 0 0 10px #1a1a2e,
    0 0 0 12px #2a2a4e,
    0 40px 80px rgba(0,0,0,0.35);
  overflow: hidden;
  position: relative;
  display: flex;
  flex-direction: column;
  flex-shrink: 0;
}

/* Notch */
.phone-frame::before {
  content: '';
  position: absolute;
  top: 0;
  left: 50%;
  transform: translateX(-50%);
  width: 120px;
  height: 30px;
  background: #1a1a2e;
  border-radius: 0 0 20px 20px;
  z-index: 100;
}

/* ─── Auth Screen ─────────────────────────────────── */
.auth-screen {
  flex: 1;
  height: 100%;
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

/* ─── Hero Section ────────────────────────────────── */
.auth-hero {
  background: linear-gradient(160deg, #deeeff 0%, #edf5ff 60%, #f5faff 100%);
  padding: 14px 24px 0;
  position: relative;
  overflow: hidden;
  flex-shrink: 0;
  height: 210px;
}

/* Status Bar inside hero */
.status-bar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  height: 34px;
  margin-bottom: 2px;
}

.status-time {
  font-size: 13px;
  font-weight: 600;
  color: #1a2b4b;
}

.status-icons {
  display: flex;
  gap: 5px;
  align-items: center;
}

.status-icons i {
  font-size: 11px;
  color: #1a2b4b;
}

.battery-text {
  font-size: 11px;
  font-weight: 600;
  color: #1a2b4b;
}

/* Logo row */
.auth-logo {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 6px;
}

.auth-logo img {
  height: 34px;
  object-fit: contain;
}

/* Hero content row: title left, illustration right */
.hero-content {
  display: flex;
  align-items: flex-end;
  justify-content: space-between;
}

.hero-text {
  flex: 1;
  padding-bottom: 12px;
}

.hero-title {
  font-size: 26px;
  font-weight: 800;
  color: #1a2b4b;
  line-height: 1.15;
  margin-bottom: 6px;
  letter-spacing: -0.3px;
}

.hero-subtitle {
  font-size: 13px;
  color: #7a8cad;
  line-height: 1.5;
  max-width: 170px;
}

.hero-illus {
  width: 130px;
  height: 120px;
  object-fit: contain;
  object-position: bottom;
  flex-shrink: 0;
  margin-right: -10px;
}

/* ─── White Form Card ─────────────────────────────── */
.auth-card {
  flex: 1;
  background: #ffffff;
  border-radius: 28px 28px 0 0;
  padding: 24px 24px 16px;
  overflow-y: auto;
  overflow-x: hidden;
  margin-top: -18px;
  position: relative;
  z-index: 10;
  /* hide scrollbar but allow scroll */
  scrollbar-width: none;
  -ms-overflow-style: none;
}

.auth-card::-webkit-scrollbar {
  display: none;
}

/* ─── Input Fields ────────────────────────────────── */
.input-group {
  display: flex;
  align-items: center;
  background: #f0f4f8;
  border-radius: 14px;
  padding: 0 16px;
  height: 52px;
  margin-bottom: 12px;
  border: 1.5px solid transparent;
  transition: border-color 0.2s, background 0.2s;
}

.input-group:focus-within {
  border-color: #2563eb;
  background: #fff;
}

.input-group i {
  font-size: 16px;
  color: #9aadc9;
  margin-right: 12px;
  width: 18px;
  flex-shrink: 0;
}

.input-group input {
  flex: 1;
  border: none;
  background: transparent;
  font-family: 'Inter', sans-serif;
  font-size: 14px;
  color: #1a2b4b;
  outline: none;
}

.input-group input::placeholder {
  color: #b0bdd0;
}

.eye-btn {
  background: none;
  border: none;
  cursor: pointer;
  padding: 4px;
  color: #b0bdd0;
  font-size: 15px;
  display: flex;
  align-items: center;
  transition: color 0.2s;
}

.eye-btn:hover {
  color: #2563eb;
}

/* ─── Checkbox Row ────────────────────────────────── */
.check-row {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 20px;
  margin-top: 4px;
}

.check-row.space-between {
  justify-content: space-between;
}

.check-left {
  display: flex;
  align-items: center;
  gap: 10px;
}

.custom-checkbox {
  width: 20px;
  height: 20px;
  border-radius: 5px;
  border: 2px solid #2563eb;
  background: #2563eb;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  cursor: pointer;
}

.custom-checkbox i {
  font-size: 11px;
  color: #fff;
}

.check-label {
  font-size: 13px;
  color: #5a6882;
}

.check-label a {
  color: #2563eb;
  font-weight: 600;
  text-decoration: none;
}

.forgot-link {
  font-size: 13px;
  color: #2563eb;
  font-weight: 600;
  text-decoration: none;
  white-space: nowrap;
}

.forgot-link:hover {
  text-decoration: underline;
}

/* ─── Primary Button ──────────────────────────────── */
.btn-primary-auth {
  display: block;
  width: 100%;
  padding: 15px;
  background: #2563eb;
  color: #fff;
  border: none;
  border-radius: 50px;
  font-family: 'Inter', sans-serif;
  font-size: 15px;
  font-weight: 700;
  cursor: pointer;
  text-align: center;
  box-shadow: 0 6px 20px rgba(37,99,235,0.35);
  transition: all 0.25s ease;
  letter-spacing: 0.2px;
  margin-bottom: 20px;
}

.btn-primary-auth:hover {
  background: #1d4ed8;
  transform: translateY(-1px);
  box-shadow: 0 8px 28px rgba(37,99,235,0.45);
}

/* ─── OR Divider ──────────────────────────────────── */
.or-divider {
  display: flex;
  align-items: center;
  gap: 12px;
  margin-bottom: 16px;
}

.or-divider::before,
.or-divider::after {
  content: '';
  flex: 1;
  height: 1px;
  background: #e8edf5;
}

.or-divider span {
  font-size: 13px;
  color: #b0bdd0;
  font-weight: 500;
}

/* ─── Social Buttons ──────────────────────────────── */
.btn-social {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 12px;
  width: 100%;
  padding: 13px;
  background: #fff;
  border: 1.5px solid #e2e8f0;
  border-radius: 50px;
  font-family: 'Inter', sans-serif;
  font-size: 14px;
  font-weight: 600;
  color: #1a2b4b;
  cursor: pointer;
  margin-bottom: 12px;
  transition: all 0.2s ease;
}

.btn-social:hover {
  border-color: #2563eb;
  background: #f8fbff;
}

.google-icon {
  width: 20px;
  height: 20px;
  flex-shrink: 0;
}

.btn-social .apple-icon {
  font-size: 18px;
  color: #1a2b4b;
}

/* ─── Bottom Link ─────────────────────────────────── */
.auth-bottom {
  text-align: center;
  padding: 14px 0 4px;
  font-size: 13.5px;
  color: #7a8cad;
}

.auth-bottom a {
  color: #2563eb;
  font-weight: 700;
  text-decoration: none;
}

.auth-bottom a:hover {
  text-decoration: underline;
}

/* ─── Responsive (actual mobile) ─────────────────── */
@media (max-width: 430px) {
  body {
    background: #f4f7fb;
    padding: 0;
    align-items: flex-start;
  }

  .phone-frame {
    width: 100%;
    height: 100vh;
    border-radius: 0;
    box-shadow: none;
  }

  .phone-frame::before {
    display: none;
  }
}

/* ── Forgot Password / Reset Password Screens ────────── */

.fp-screen {
  flex: 1;
  height: 100%;
  background: linear-gradient(170deg, #deeeff 0%, #ecf5ff 40%, #f5faff 100%);
  display: flex;
  flex-direction: column;
  overflow: hidden;
  padding: 0 24px;
}

/* Override body padding from auth.css for this layout */
.fp-screen .status-bar {
  padding: 14px 0 0;
  height: 48px;
  flex-shrink: 0;
}

/* Logo row */
.fp-logo {
  margin-bottom: 6px;
  flex-shrink: 0;
}

.fp-logo img {
  height: 36px;
  object-fit: contain;
}

/* ── Title + Illustration ─────────────────────────── */
.fp-top {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  margin-bottom: 18px;
  flex-shrink: 0;
  min-height: 130px;
}

.fp-title-block {
  flex: 1;
  padding-top: 4px;
}

.fp-title {
  font-size: 28px;
  font-weight: 800;
  color: #1a2b4b;
  line-height: 1.15;
  margin-bottom: 10px;
  letter-spacing: -0.4px;
}

.fp-subtitle {
  font-size: 13px;
  color: #7a8cad;
  line-height: 1.55;
  max-width: 185px;
}

/* Circular illustration bubble */
.fp-illus-wrap {
  flex-shrink: 0;
  margin-left: 10px;
}

.fp-illus-bubble {
  width: 110px;
  height: 110px;
  border-radius: 50%;
  background: linear-gradient(135deg, #dbeafe 0%, #c7d9f8 100%);
  overflow: hidden;
  display: flex;
  align-items: flex-end;
  justify-content: center;
}

.fp-illus {
  width: 110px;
  height: 110px;
  object-fit: cover;
  object-position: top center;
}

/* ── White Card ───────────────────────────────────── */
.fp-card {
  background: #ffffff;
  border-radius: 24px;
  padding: 22px 20px 18px;
  box-shadow: 0 8px 40px rgba(37, 99, 235, 0.09), 0 2px 12px rgba(0,0,0,0.05);
  flex-shrink: 0;
}

.fp-card-tall {
  padding: 20px 20px 16px;
}

/* Field label (used in create new password) */
.fp-field-label {
  font-size: 13.5px;
  font-weight: 600;
  color: #1a2b4b;
  margin-bottom: 8px;
  margin-top: 4px;
}

/* Override input-group margin inside fp-card */
.fp-card .input-group {
  margin-bottom: 14px;
}

/* Back to Login link */
.fp-back-link {
  text-align: center;
  padding-top: 4px;
}

.fp-back-link a {
  font-size: 14px;
  font-weight: 700;
  color: #2563eb;
  text-decoration: none;
}

.fp-back-link a:hover {
  text-decoration: underline;
}

/* btn inside fp-card */
.fp-card .btn-primary-auth {
  margin-bottom: 14px;
}

/* ── Hint Row ─────────────────────────────────────── */
.fp-hint {
  display: flex;
  align-items: center;
  gap: 12px;
  margin-top: 18px;
  padding: 0 4px;
  flex-shrink: 0;
}

.hint-icon {
  width: 38px;
  height: 38px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  font-size: 16px;
}

.hint-teal {
  background: #e6faf5;
  color: #0ea98b;
  border: 1.5px solid #b6f0e1;
}

.hint-green {
  background: #dcfce7;
  color: #16a34a;
  border: 1.5px solid #bbf7d0;
}

.hint-text {
  font-size: 13px;
  color: #7a8cad;
  line-height: 1.5;
}

/* ── Home Bar ─────────────────────────────────────── */
.home-bar {
  width: 120px;
  height: 4px;
  background: #c8d9ee;
  border-radius: 4px;
  margin: auto auto 16px;
  flex-shrink: 0;
}
